const { ethers } = require('ethers');

class TokenSwapper {
  constructor(provider, wallet) {
    this.provider = provider;
    this.wallet = wallet;
    this.signer = wallet.connect(provider);
  }

  async approveToken(tokenAddress, spenderAddress, amount = ethers.constants.MaxUint256) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, [
        'function approve(address spender, uint256 amount) public returns (bool)'
      ], this.signer);
      
      const tx = await tokenContract.approve(spenderAddress, amount);
      await tx.wait();
      return tx;
    } catch (error) {
      throw new Error(`Approval failed: ${error.message}`);
    }
  }

  async swapTokens(tokenInAddress, tokenOutAddress, amountIn, amountOutMin, recipient) {
    try {
      const routerAddress = '0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D'; // Uniswap V2 Router
      
      const routerContract = new ethers.Contract(routerAddress, [
        'function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external returns (uint256[] memory amounts)'
      ], this.signer);
      
      const deadline = Math.floor(Date.now() / 1000) + 60 * 10; // 10 minutes from now
      const path = [tokenInAddress, tokenOutAddress];
      
      const tx = await routerContract.swapExactTokensForTokens(
        amountIn,
        amountOutMin,
        path,
        recipient,
        deadline
      );
      
      await tx.wait();
      return tx;
    } catch (error) {
      throw new Error(`Swap failed: ${error.message}`);
    }
  }

  async getAllowance(tokenAddress, spenderAddress) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, [
        'function allowance(address owner, address spender) public view returns (uint256)'
      ], this.provider);
      
      return await tokenContract.allowance(this.wallet.address, spenderAddress);
    } catch (error) {
      throw new Error(`Failed to get allowance: ${error.message}`);
    }
  }

  async getTokenBalance(tokenAddress) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, [
        'function balanceOf(address account) public view returns (uint256)'
      ], this.provider);
      
      return await tokenContract.balanceOf(this.wallet.address);
    } catch (error) {
      throw new Error(`Failed to get balance: ${error.message}`);
    }
  }

  async getSwapQuote(tokenInAddress, tokenOutAddress, amountIn) {
    try {
      const routerAddress = '0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D';
      
      const routerContract = new ethers.Contract(routerAddress, [
        'function getAmountsOut(uint256 amountIn, address[] calldata path) external view returns (uint256[] memory amounts)'
      ], this.provider);
      
      const path = [tokenInAddress, tokenOutAddress];
      const amounts = await routerContract.getAmountsOut(amountIn, path);
      
      return {
        amountIn: amountIn,
        amountOut: amounts[1],
        path: path
      };
    } catch (error) {
      throw new Error(`Failed to get quote: ${error.message}`);
    }
  }
}

